func createGIFThumbnailSource(width, height int) []byte {
	img := image.NewPaletted(image.Rect(0, 0, width, height), color.Palette{
		color.RGBA{0, 0, 0, 255},
		color.RGBA{255, 255, 255, 255},
	})
	for y := 0; y < height; y++ {
		for x := 0; x < width; x++ {
			if (x+y)%2 == 0 {
				img.SetColorIndex(x, y, 1)
			}
		}
	}

	var buf bytes.Buffer
	if err := gif.Encode(&buf, img, nil); err != nil {
		panic(err)
	}
	return buf.Bytes()
}

func createPNGThumbnailSourceWithAlpha(width, height int) []byte {
	img := image.NewNRGBA(image.Rect(0, 0, width, height))
	for y := 0; y < height; y++ {
		for x := 0; x < width; x++ {
			img.Set(x, y, color.NRGBA{R: 32, G: 160, B: 224, A: 128})
		}
	}

	var buf bytes.Buffer
	if err := png.Encode(&buf, img); err != nil {
		panic(err)
	}
	return buf.Bytes()
}

func uniqueVersionTestContent(t *testing.T, label string) []byte {
	t.Helper()
	return []byte(fmt.Sprintf("%s:%s", t.Name(), label))
}

func uniqueSixByteVersionTestContent(t *testing.T, label string) []byte {
	t.Helper()
	return []byte(fmt.Sprintf("%06x", crc32.ChecksumIEEE(uniqueVersionTestContent(t, label)))[:6])
}

// testDataplaneAddr is the address of the test dataplane server
func testDataplaneAddr() string {
	if addr := os.Getenv("MNEMONAS_TEST_DATAPLANE_ADDR"); addr != "" {
		return addr
	}
	return "127.0.0.1:9090"
}

type fakeAlertMonitor struct {
	mu          sync.Mutex
	updateCount int
	lastConfig  alerts.Config
	lastStats   *alerts.StorageStats
	events      []alerts.EventPayload
	eventCh     chan alerts.EventPayload
	sendErr     error
}

func (m *fakeAlertMonitor) UpdateConfig(cfg alerts.Config) {
	m.mu.Lock()
	defer m.mu.Unlock()
	m.updateCount++
	m.lastConfig = cfg
}

func (m *fakeAlertMonitor) LastStats() *alerts.StorageStats {
	m.mu.Lock()
	defer m.mu.Unlock()
	if m.lastStats == nil {
		return nil
	}
	clone := *m.lastStats
	return &clone
}

func (m *fakeAlertMonitor) SendEvent(_ context.Context, event alerts.EventPayload) error {
	m.mu.Lock()
	if m.sendErr != nil {
		m.mu.Unlock()
		return m.sendErr
	}
	m.events = append(m.events, event)
	eventCh := m.eventCh
	m.mu.Unlock()
	if eventCh != nil {
		select {
		case eventCh <- event:
		default:
		}
	}
	return nil
}

func (m *fakeAlertMonitor) eventNotifications() <-chan alerts.EventPayload {
	m.mu.Lock()
	defer m.mu.Unlock()
	if m.eventCh == nil {
		m.eventCh = make(chan alerts.EventPayload, 16)
	}
	return m.eventCh
}

func fakeAlertEventByType(monitor *fakeAlertMonitor, eventType string) (alerts.EventPayload, bool) {
	monitor.mu.Lock()
	defer monitor.mu.Unlock()
	for _, event := range monitor.events {
		if event.Type == eventType {
			return event, true
		}
	}
	return alerts.EventPayload{}, false
}

func waitForFakeAlertEvent(t *testing.T, monitor *fakeAlertMonitor, eventType string) alerts.EventPayload {
	t.Helper()
	eventCh := monitor.eventNotifications()
	timer := time.NewTimer(time.Second)
	defer timer.Stop()
	for {
		if event, ok := fakeAlertEventByType(monitor, eventType); ok {
			return event
		}
		select {
		case event := <-eventCh:
			if event.Type == eventType {
				return event
			}
		case <-timer.C:
			t.Fatalf("timed out waiting for alert event %q", eventType)
		}
	}
}

func fakeAlertEventCount(monitor *fakeAlertMonitor) int {
	monitor.mu.Lock()
	defer monitor.mu.Unlock()
	return len(monitor.events)
}

func requireQuotaAlertHidesPaths(t *testing.T, event alerts.EventPayload, forbiddenFragments ...string) {
	t.Helper()
	for _, key := range []string{"target_path", "home_dir", "quota_path", "username"} {
		if _, ok := event.Details[key]; ok {
			t.Fatalf("quota alert detail %q should be omitted: %+v", key, event.Details)
		}
	}
	data, err := json.Marshal(event.Details)
	if err != nil {
		t.Fatalf("marshal quota alert details: %v", err)
	}
	for _, fragment := range forbiddenFragments {
		if fragment == "" {
			continue
		}
		if strings.Contains(string(data), fragment) {
			t.Fatalf("quota alert details leaked %q: %s", fragment, data)
		}
	}
}

func TestServer_SendQuotaExceededAlertEventIgnoresDisabledUserContext(t *testing.T) {
	monitor := &fakeAlertMonitor{}
	server := &Server{alertMonitor: monitor, logger: zerolog.Nop()}
	ctx := context.WithValue(context.Background(), auth.ContextKeyUser, &auth.User{
		ID:       "disabled-user",
		Username: "disabled-user",
		Disabled: true,
	})

	server.sendQuotaExceededAlertEvent(ctx, "upload", newQuotaExceededErrorFor(quotaTypeUser, "/disabled-user", 5, 4, 2, 0))

	if len(monitor.events) != 1 {
		t.Fatalf("quota alert event count = %d, want 1", len(monitor.events))
	}
	if got := monitor.events[0].Details["actor_scope"]; got != "unknown" {
		t.Fatalf("actor_scope = %q, want unknown", got)
	}
}

func requireQuotaResponsePath(t *testing.T, body, wantPath string, forbiddenFragments ...string) {
	t.Helper()
	var payload struct {
		Details struct {
			QuotaType string `json:"quota_type"`
			QuotaPath string `json:"quota_path"`
		} `json:"details"`
	}
	if err := json.Unmarshal([]byte(body), &payload); err != nil {
		t.Fatalf("decode quota response: %v; body=%s", err, body)
	}
	if payload.Details.QuotaType != quotaTypeDirectory || payload.Details.QuotaPath != wantPath {
		t.Fatalf("expected directory quota details with path %q, got %+v; body=%s", wantPath, payload.Details, body)
	}
	for _, fragment := range forbiddenFragments {
		if fragment == "" {
			continue
		}
		if strings.Contains(body, fragment) {
			t.Fatalf("quota response leaked %q: %s", fragment, body)
		}
	}
}

type fakeRetentionMonitor struct {
	updateCount  int
	lastConfig   storage.RetentionMonitorConfig
	lastPolicy   storage.RuntimePolicySettings
	fs           *storage.FileSystem
	policyBefore storage.DeletePolicy
}

func (m *fakeRetentionMonitor) UpdateConfigAndRuntimePolicy(cfg storage.RetentionMonitorConfig, policy storage.RuntimePolicySettings) {
	m.updateCount++
	m.lastConfig = cfg
	m.lastPolicy = policy
	if m.fs != nil {
		m.policyBefore = m.fs.CurrentDeletePolicy()
		m.fs.UpdateRuntimePolicySettings(policy)
	}
}

type fakeDiskHealthMonitor struct {
	updateCount int
	lastConfig  diskhealth.Config
	report      *diskhealth.Report
	checkErr    error
	recorder    diskhealth.Recorder
}

func (m *fakeDiskHealthMonitor) Check(context.Context) (*diskhealth.Report, error) {
	if m.checkErr != nil {
		return nil, m.checkErr
	}
	return cloneDiskHealthReport(m.report), nil
}

func (m *fakeDiskHealthMonitor) LastReport() *diskhealth.Report {
	return cloneDiskHealthReport(m.report)
}

func (m *fakeDiskHealthMonitor) UpdateConfig(cfg diskhealth.Config) {
	m.updateCount++
	m.lastConfig = cfg
}

func (m *fakeDiskHealthMonitor) SetActivityRecorder(recorder diskhealth.Recorder) {
	m.recorder = recorder
}

func cloneDiskHealthReport(report *diskhealth.Report) *diskhealth.Report {
	if report == nil {
		return nil
	}
	clone := *report
	clone.Devices = append([]diskhealth.DeviceStatus(nil), report.Devices...)
	clone.Warnings = append([]string(nil), report.Warnings...)
	return &clone
}

