func TestDownloadArchiveChildPathRejectsEntriesOutsideSource(t *testing.T) {
	tests := []struct {
		name       string
		sourcePath string
		child      *storage.FileInfo
		wantPath   string
		wantName   string
		wantErr    bool
	}{
		{
			name:       "direct child",
			sourcePath: "/docs",
			child:      &storage.FileInfo{Path: "/docs/report.txt", Name: "report.txt"},
			wantPath:   "/docs/report.txt",
			wantName:   "report.txt",
		},
		{
			name:       "fallback from blank path",
			sourcePath: "/docs",
			child:      &storage.FileInfo{Name: "report.txt"},
			wantPath:   "/docs/report.txt",
			wantName:   "report.txt",
		},
		{
			name:       "whitespace child path",
			sourcePath: "/docs",
			child:      &storage.FileInfo{Path: "   ", Name: "report.txt"},
			wantErr:    true,
		},
		{
			name:       "similar prefix sibling",
			sourcePath: "/docs",
			child:      &storage.FileInfo{Path: "/docs-archive/secret.txt", Name: "secret.txt"},
			wantErr:    true,
		},
		{
			name:       "nested descendant",
			sourcePath: "/docs",
			child:      &storage.FileInfo{Path: "/docs/nested/secret.txt", Name: "secret.txt"},
			wantErr:    true,
		},
		{
			name:       "same directory path",
			sourcePath: "/docs",
			child:      &storage.FileInfo{Path: "/docs", Name: "docs"},
			wantErr:    true,
		},
		{
			name:       "root source rejects root child",
			sourcePath: "/",
			child:      &storage.FileInfo{Path: "/", Name: "/"},
			wantErr:    true,
		},
		{
			name:       "dot segment child path",
			sourcePath: "/docs",
			child:      &storage.FileInfo{Path: "/docs/./report.txt", Name: "report.txt"},
			wantErr:    true,
		},
		{
			name:       "dot segment fallback name",
			sourcePath: "/docs",
			child:      &storage.FileInfo{Name: "./report.txt"},
			wantErr:    true,
		},
		{
			name:       "leading slash fallback name",
			sourcePath: "/docs",
			child:      &storage.FileInfo{Name: "/report.txt"},
			wantErr:    true,
		},
		{
			name:       "trailing slash fallback name",
			sourcePath: "/docs",
			child:      &storage.FileInfo{Name: "report.txt/"},
			wantErr:    true,
		},
		{
			name:       "backslash fallback name",
			sourcePath: "/docs",
			child:      &storage.FileInfo{Name: "nested\\report.txt"},
			wantErr:    true,
		},
		{
			name:       "control character child path",
			sourcePath: "/docs",
			child:      &storage.FileInfo{Path: "/docs/report\n2026.txt", Name: "report\n2026.txt"},
			wantErr:    true,
		},
		{
			name:       "backslash child path",
			sourcePath: "/docs",
			child:      &storage.FileInfo{Path: "/docs\\report.txt", Name: "report.txt"},
			wantErr:    true,
		},
		{
			name:       "control character fallback name",
			sourcePath: "/docs",
			child:      &storage.FileInfo{Name: "report\x7f.txt"},
			wantErr:    true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			gotPath, gotName, err := downloadArchiveChildPath(tt.sourcePath, tt.child)
			if (err != nil) != tt.wantErr {
				t.Fatalf("downloadArchiveChildPath() error = %v, wantErr %v", err, tt.wantErr)
			}
			if gotPath != tt.wantPath {
				t.Fatalf("downloadArchiveChildPath() = %q, want %q", gotPath, tt.wantPath)
			}
			if gotName != tt.wantName {
				t.Fatalf("downloadArchiveChildPath() name = %q, want %q", gotName, tt.wantName)
			}
		})
	}
}

func TestSafeDownloadArchiveEntryNameRejectsDotSegments(t *testing.T) {
	for _, name := range []string{
		"docs/./report.txt",
		"docs/../report.txt",
		"./docs/report.txt",
		"C:/windows/system32/config",
		"c:relative-drive-path.txt",
		"docs/C:windows/system32/config",
		"docs/report.txt:stream",
		"docs/report\n2026.txt",
		"docs/report\x7f.txt",
	} {
		if got, err := safeDownloadArchiveEntryName(name); err == nil {
			t.Fatalf("safeDownloadArchiveEntryName(%q) = %q, want error", name, got)
		}
	}

	got, err := safeDownloadArchiveEntryName("docs/foo..txt")
	if err != nil {
		t.Fatalf("safeDownloadArchiveEntryName(foo..txt) error: %v", err)
	}
	if got != "docs/foo..txt" {
		t.Fatalf("safeDownloadArchiveEntryName(foo..txt) = %q, want docs/foo..txt", got)
	}
}

func TestServer_WriteDownloadArchiveRejectsUnsafeHeaderNames(t *testing.T) {
	server, fs, _ := setupTestServer(t)
	ctx := context.Background()

	if err := fs.WriteFile(ctx, "/safe.txt", bytes.NewReader([]byte("safe"))); err != nil {
		t.Fatalf("WriteFile(/safe.txt) error: %v", err)
	}

	now := time.Unix(1700000000, 0)
	tests := []struct {
		name  string
		entry downloadArchiveEntry
	}{
		{
			name: "directory traversal",
			entry: downloadArchiveEntry{
				sourcePath: "/safe-dir",
				zipName:    "../evil/",
				info: &storage.FileInfo{
					Path:    "/safe-dir",
					Name:    "safe-dir",
					IsDir:   true,
					ModTime: now,
				},
			},
		},
		{
			name: "file absolute path",
			entry: downloadArchiveEntry{
				sourcePath: "/safe.txt",
				zipName:    "/evil.txt",
				info: &storage.FileInfo{
					Path:    "/safe.txt",
					Name:    "safe.txt",
					Size:    4,
					ModTime: now,
				},
			},
		},
		{
			name: "file parent segment",
			entry: downloadArchiveEntry{
				sourcePath: "/safe.txt",
				zipName:    "docs/../evil.txt",
				info: &storage.FileInfo{
					Path:    "/safe.txt",
					Name:    "safe.txt",
					Size:    4,
					ModTime: now,
				},
			},
		},
		{
			name: "file backslash separator",
			entry: downloadArchiveEntry{
				sourcePath: "/safe.txt",
				zipName:    `docs\evil.txt`,
				info: &storage.FileInfo{
					Path:    "/safe.txt",
					Name:    "safe.txt",
					Size:    4,
					ModTime: now,
				},
			},
		},
		{
			name: "file Windows drive path",
			entry: downloadArchiveEntry{
				sourcePath: "/safe.txt",
				zipName:    "C:/windows/system32/config",
				info: &storage.FileInfo{
					Path:    "/safe.txt",
					Name:    "safe.txt",
					Size:    4,
					ModTime: now,
				},
			},
		},
		{
			name: "file colon stream path",
			entry: downloadArchiveEntry{
				sourcePath: "/safe.txt",
				zipName:    "docs/report.txt:stream",
				info: &storage.FileInfo{
					Path:    "/safe.txt",
					Name:    "safe.txt",
					Size:    4,
					ModTime: now,
				},
			},
		},
		{
			name: "file trailing slash",
			entry: downloadArchiveEntry{
				sourcePath: "/safe.txt",
				zipName:    "safe.txt/",
				info: &storage.FileInfo{
					Path:    "/safe.txt",
					Name:    "safe.txt",
					Size:    4,
					ModTime: now,
				},
			},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			var archive bytes.Buffer
			zipWriter := zip.NewWriter(&archive)

			err := server.writeDownloadArchive(ctx, zipWriter, []downloadArchiveEntry{tt.entry})
			if !errors.Is(err, errInvalidPath) {
				t.Fatalf("writeDownloadArchive() error = %v, want errInvalidPath", err)
			}
			if closeErr := zipWriter.Close(); closeErr != nil {
				t.Fatalf("zipWriter.Close() error: %v", closeErr)
			}
		})
	}
}

