func TestServer_DownloadWithQueryAuth(t *testing.T) {
	server, fs, _, username, password := setupAuthServer(t)
	ctx := context.Background()

	if err := fs.Mkdir(ctx, "/"+username); err != nil {
		t.Fatalf("Mkdir(/%s) error: %v", username, err)
	}
	if err := fs.WriteFile(ctx, "/"+username+"/file.txt", bytes.NewReader([]byte("secure"))); err != nil {
		t.Fatalf("WriteFile(/%s/file.txt) error: %v", username, err)
	}

	loginBody := fmt.Sprintf(`{"username":"%s","password":"%s"}`, username, password)
	loginReq := httptest.NewRequest("POST", "/api/v1/auth/login", strings.NewReader(loginBody))
	loginRec := httptest.NewRecorder()
	server.Router().ServeHTTP(loginRec, loginReq)

	if loginRec.Code != http.StatusOK {
		t.Fatalf("login status = %d, want %d", loginRec.Code, http.StatusOK)
	}

	var loginResp auth.LoginResponse
	var loginPayload struct {
		Data auth.LoginResponse `json:"data"`
	}
	if err := json.Unmarshal(loginRec.Body.Bytes(), &loginPayload); err != nil {
		t.Fatalf("failed to parse login response: %v", err)
	}
	loginResp = loginPayload.Data

	downloadSessionReq := httptest.NewRequest(http.MethodPost, "/api/v1/auth/download-session", nil)
	downloadSessionReq.Header.Set("Authorization", "Bearer "+loginResp.AccessToken)
	downloadSessionRec := httptest.NewRecorder()
	server.Router().ServeHTTP(downloadSessionRec, downloadSessionReq)

	if downloadSessionRec.Code != http.StatusOK {
		t.Fatalf("download session status = %d, want %d", downloadSessionRec.Code, http.StatusOK)
	}
	cookies := downloadSessionRec.Result().Cookies()
	if len(cookies) == 0 {
		t.Fatal("expected download session cookie")
	}
	downloadReq := httptest.NewRequest("GET", "/api/v1/download/"+username+"/file.txt", nil)
	downloadReq.AddCookie(cookies[0])
	downloadRec := httptest.NewRecorder()
	server.Router().ServeHTTP(downloadRec, downloadReq)

	if downloadRec.Code != http.StatusOK {
		t.Fatalf("download status = %d, want %d", downloadRec.Code, http.StatusOK)
	}
	if !strings.Contains(downloadRec.Body.String(), "secure") {
		t.Error("downloaded content mismatch")
	}
}

func TestServer_CookieSessionLoginCreatesDownloadSession(t *testing.T) {
	server, _, _, username, password := setupAuthServer(t)

	loginBody := fmt.Sprintf(`{"username":"%s","password":"%s"}`, username, password)
	loginReq := httptest.NewRequest(http.MethodPost, "/api/v1/auth/login", strings.NewReader(loginBody))
	loginReq.Header.Set("Content-Type", "application/json")
	loginReq.Header.Set("X-MnemoNAS-Session-Mode", "cookie")
	loginRec := httptest.NewRecorder()
	server.Router().ServeHTTP(loginRec, loginReq)

	if loginRec.Code != http.StatusOK {
		t.Fatalf("login status = %d, want %d; body=%s", loginRec.Code, http.StatusOK, loginRec.Body.String())
	}

	var loginPayload struct {
		Data auth.LoginResponse `json:"data"`
	}
	if err := json.Unmarshal(loginRec.Body.Bytes(), &loginPayload); err != nil {
		t.Fatalf("failed to parse login response: %v", err)
	}
	if loginPayload.Data.AccessToken != "" || loginPayload.Data.RefreshToken != "" {
		t.Fatalf("cookie-session login leaked bearer tokens: %+v", loginPayload.Data)
	}

	var accessCookie *http.Cookie
	for _, cookie := range loginRec.Result().Cookies() {
		if cookie.Name == auth.AccessSessionCookieName {
			accessCookie = cookie
			break
		}
	}
	if accessCookie == nil {
		t.Fatalf("login did not set %s cookie; cookies=%+v", auth.AccessSessionCookieName, loginRec.Result().Cookies())
	}
	if !accessCookie.HttpOnly {
		t.Fatal("access cookie is not HttpOnly")
	}
	if accessCookie.Path != "/api/v1" {
		t.Fatalf("access cookie Path = %q, want %q", accessCookie.Path, "/api/v1")
	}

	downloadSessionReq := httptest.NewRequest(http.MethodPost, "/api/v1/auth/download-session", nil)
	downloadSessionReq.AddCookie(accessCookie)
	downloadSessionRec := httptest.NewRecorder()
	server.Router().ServeHTTP(downloadSessionRec, downloadSessionReq)

	if downloadSessionRec.Code != http.StatusOK {
		t.Fatalf("download session status = %d, want %d; body=%s", downloadSessionRec.Code, http.StatusOK, downloadSessionRec.Body.String())
	}

	var downloadCookie *http.Cookie
	for _, cookie := range downloadSessionRec.Result().Cookies() {
		if cookie.Name == auth.DownloadSessionCookieName {
			downloadCookie = cookie
			break
		}
	}
	if downloadCookie == nil {
		t.Fatalf("download session did not set %s cookie; cookies=%+v", auth.DownloadSessionCookieName, downloadSessionRec.Result().Cookies())
	}
	if !downloadCookie.HttpOnly {
		t.Fatal("download session cookie is not HttpOnly")
	}
	if downloadCookie.Path != "/api/v1" {
		t.Fatalf("download session cookie Path = %q, want %q", downloadCookie.Path, "/api/v1")
	}
	if downloadCookie.SameSite != http.SameSiteStrictMode {
		t.Fatalf("download session cookie SameSite = %v, want Strict", downloadCookie.SameSite)
	}
}

func TestServer_DownloadSession_UsesRouteAuthContract(t *testing.T) {
	server, _, _, username, password := setupAuthServer(t)

	decodeErrorCode := func(t *testing.T, body []byte) string {
		t.Helper()

		var envelope struct {
			Error *struct {
				Code string `json:"code"`
			} `json:"error"`
		}
		if err := json.Unmarshal(body, &envelope); err != nil {
			t.Fatalf("failed to decode response: %v", err)
		}
		if envelope.Error == nil {
			t.Fatalf("expected structured error response, got %s", string(body))
		}
		return envelope.Error.Code
	}

	t.Run("missing authorization header", func(t *testing.T) {
		req := httptest.NewRequest(http.MethodPost, "/api/v1/auth/download-session", nil)
		rec := httptest.NewRecorder()

		server.Router().ServeHTTP(rec, req)

		if rec.Code != http.StatusUnauthorized {
			t.Fatalf("status = %d, want %d; body=%s", rec.Code, http.StatusUnauthorized, rec.Body.String())
		}
		if got := decodeErrorCode(t, rec.Body.Bytes()); got != "MISSING_AUTH_HEADER" {
			t.Fatalf("error code = %q, want %q", got, "MISSING_AUTH_HEADER")
		}
	})

	t.Run("revoked access token", func(t *testing.T) {
		loginBody := fmt.Sprintf(`{"username":"%s","password":"%s"}`, username, password)
		loginReq := httptest.NewRequest(http.MethodPost, "/api/v1/auth/login", strings.NewReader(loginBody))
		loginRec := httptest.NewRecorder()
		server.Router().ServeHTTP(loginRec, loginReq)

		if loginRec.Code != http.StatusOK {
			t.Fatalf("login status = %d, want %d", loginRec.Code, http.StatusOK)
		}

		var loginPayload struct {
			Data auth.LoginResponse `json:"data"`
		}
		if err := json.Unmarshal(loginRec.Body.Bytes(), &loginPayload); err != nil {
			t.Fatalf("failed to decode login response: %v", err)
		}

		logoutReq := httptest.NewRequest(http.MethodPost, "/api/v1/auth/logout", nil)
		logoutReq.Header.Set("Authorization", "Bearer "+loginPayload.Data.AccessToken)
		logoutRec := httptest.NewRecorder()
		server.Router().ServeHTTP(logoutRec, logoutReq)

		if logoutRec.Code != http.StatusOK {
			t.Fatalf("logout status = %d, want %d; body=%s", logoutRec.Code, http.StatusOK, logoutRec.Body.String())
		}

		req := httptest.NewRequest(http.MethodPost, "/api/v1/auth/download-session", nil)
		req.Header.Set("Authorization", "Bearer "+loginPayload.Data.AccessToken)
		rec := httptest.NewRecorder()

		server.Router().ServeHTTP(rec, req)

		if rec.Code != http.StatusUnauthorized {
			t.Fatalf("status = %d, want %d; body=%s", rec.Code, http.StatusUnauthorized, rec.Body.String())
		}
		if got := decodeErrorCode(t, rec.Body.Bytes()); got != "TOKEN_REVOKED" {
			t.Fatalf("error code = %q, want %q", got, "TOKEN_REVOKED")
		}
	})
}

func TestServer_Logout_ClearsCookiesWithoutValidAuth(t *testing.T) {
	server, _, _, _, _ := setupAuthServer(t)

	req := httptest.NewRequest(http.MethodPost, "/api/v1/auth/logout", nil)
	req.AddCookie(&http.Cookie{Name: auth.AccessSessionCookieName, Value: "stale"})
	req.AddCookie(&http.Cookie{Name: auth.RefreshSessionCookieName, Value: "stale"})
	req.AddCookie(&http.Cookie{Name: auth.DownloadSessionCookieName, Value: "stale"})
	rec := httptest.NewRecorder()

	server.Router().ServeHTTP(rec, req)

	if rec.Code != http.StatusOK {
		t.Fatalf("logout status = %d, want %d; body=%s", rec.Code, http.StatusOK, rec.Body.String())
	}

	cleared := map[string]bool{}
	for _, cookie := range rec.Result().Cookies() {
		if cookie.MaxAge != -1 {
			t.Fatalf("cookie %s MaxAge = %d, want -1", cookie.Name, cookie.MaxAge)
		}
		cleared[cookie.Name] = true
	}
	for _, name := range []string{
		string(auth.AccessSessionCookieName),
		string(auth.RefreshSessionCookieName),
		string(auth.DownloadSessionCookieName),
	} {
		if !cleared[name] {
			t.Fatalf("expected logout to clear cookie %s, got %+v", name, rec.Result().Cookies())
		}
	}
}

func TestServer_Logout_AllowsPasswordChangeRequiredSession(t *testing.T) {
	server, _ := setupAuthSettingsServer(t)
	admin, err := server.userStore.GetByUsername("admin")
	if err != nil {
		t.Fatalf("GetByUsername(admin) error: %v", err)
	}
	const temporaryPassword = "temporary-password"
	if err := server.userStore.ResetPassword(admin.ID, temporaryPassword); err != nil {
		t.Fatalf("ResetPassword(admin) error: %v", err)
	}

	loginRequest := httptest.NewRequest(
		http.MethodPost,
		"/api/v1/auth/login",
		strings.NewReader(`{"username":"admin","password":"temporary-password"}`),
	)
	loginRequest.Header.Set("Content-Type", "application/json")
	loginResponse := httptest.NewRecorder()
	server.Router().ServeHTTP(loginResponse, loginRequest)
	if loginResponse.Code != http.StatusOK {
		t.Fatalf("login status = %d, want %d; body=%s", loginResponse.Code, http.StatusOK, loginResponse.Body.String())
	}

	var loginPayload struct {
		Data auth.LoginResponse `json:"data"`
	}
	if err := json.Unmarshal(loginResponse.Body.Bytes(), &loginPayload); err != nil {
		t.Fatalf("decode login response: %v", err)
	}
	if !loginPayload.Data.User.MustChangePassword {
		t.Fatal("login response did not require password change")
	}

	logoutRequest := httptest.NewRequest(http.MethodPost, "/api/v1/auth/logout", nil)
	logoutRequest.Header.Set("Authorization", "Bearer "+loginPayload.Data.AccessToken)
	logoutResponse := httptest.NewRecorder()
	server.Router().ServeHTTP(logoutResponse, logoutRequest)
	if logoutResponse.Code != http.StatusOK {
		t.Fatalf("logout status = %d, want %d; body=%s", logoutResponse.Code, http.StatusOK, logoutResponse.Body.String())
	}
	if _, err := server.tokenManager.ValidateAccessToken(loginPayload.Data.AccessToken); !errors.Is(err, auth.ErrTokenRevoked) {
		t.Fatalf("access token validation after logout = %v, want %v", err, auth.ErrTokenRevoked)
	}
}

