func TestServer_RejectsCrossOriginUnsafeBrowserRequests(t *testing.T) {
	server, _, _, username, password := setupAuthServer(t)
	loginBody := fmt.Sprintf(`{"username":"%s","password":"%s"}`, username, password)

	crossOriginReq := httptest.NewRequest(http.MethodPost, "https://nas.example.test/api/v1/auth/login", strings.NewReader(loginBody))
	crossOriginReq.Header.Set("Content-Type", "application/json")
	crossOriginReq.Header.Set("Origin", "https://evil.example.test")
	crossOriginRec := httptest.NewRecorder()

	server.Router().ServeHTTP(crossOriginRec, crossOriginReq)

	if crossOriginRec.Code != http.StatusForbidden {
		t.Fatalf("cross-origin login status = %d, want %d; body=%s", crossOriginRec.Code, http.StatusForbidden, crossOriginRec.Body.String())
	}

	crossSchemeReq := httptest.NewRequest(http.MethodPost, "https://nas.example.test/api/v1/auth/login", strings.NewReader(loginBody))
	crossSchemeReq.Header.Set("Content-Type", "application/json")
	crossSchemeReq.Header.Set("Origin", "http://nas.example.test")
	crossSchemeRec := httptest.NewRecorder()

	server.Router().ServeHTTP(crossSchemeRec, crossSchemeReq)

	if crossSchemeRec.Code != http.StatusForbidden {
		t.Fatalf("cross-scheme login status = %d, want %d; body=%s", crossSchemeRec.Code, http.StatusForbidden, crossSchemeRec.Body.String())
	}

	wrongPortReq := httptest.NewRequest(http.MethodPost, "https://nas.example.test/api/v1/auth/login", strings.NewReader(loginBody))
	wrongPortReq.Header.Set("Content-Type", "application/json")
	wrongPortReq.Header.Set("Origin", "https://nas.example.test:80")
	wrongPortRec := httptest.NewRecorder()

	server.Router().ServeHTTP(wrongPortRec, wrongPortReq)

	if wrongPortRec.Code != http.StatusForbidden {
		t.Fatalf("wrong-port login status = %d, want %d; body=%s", wrongPortRec.Code, http.StatusForbidden, wrongPortRec.Body.String())
	}

	fetchSiteReq := httptest.NewRequest(http.MethodPost, "https://nas.example.test/api/v1/auth/login", strings.NewReader(loginBody))
	fetchSiteReq.Header.Set("Content-Type", "application/json")
	fetchSiteReq.Header.Set("Sec-Fetch-Site", "cross-site")
	fetchSiteRec := httptest.NewRecorder()

	server.Router().ServeHTTP(fetchSiteRec, fetchSiteReq)

	if fetchSiteRec.Code != http.StatusForbidden {
		t.Fatalf("cross-site fetch metadata login status = %d, want %d; body=%s", fetchSiteRec.Code, http.StatusForbidden, fetchSiteRec.Body.String())
	}

	sameSiteReq := httptest.NewRequest(http.MethodPost, "https://nas.example.test/api/v1/auth/login", strings.NewReader(loginBody))
	sameSiteReq.Header.Set("Content-Type", "application/json")
	sameSiteReq.Header.Set("Sec-Fetch-Site", "same-site")
	sameSiteRec := httptest.NewRecorder()

	server.Router().ServeHTTP(sameSiteRec, sameSiteReq)

	if sameSiteRec.Code != http.StatusForbidden {
		t.Fatalf("same-site fetch metadata login status = %d, want %d; body=%s", sameSiteRec.Code, http.StatusForbidden, sameSiteRec.Body.String())
	}

	sameOriginReq := httptest.NewRequest(http.MethodPost, "https://nas.example.test/api/v1/auth/login", strings.NewReader(loginBody))
	sameOriginReq.Host = "nas.example.test:443"
	sameOriginReq.Header.Set("Content-Type", "application/json")
	sameOriginReq.Header.Set("Origin", "https://nas.example.test")
	sameOriginReq.Header.Set("Sec-Fetch-Site", "same-origin")
	sameOriginRec := httptest.NewRecorder()

	server.Router().ServeHTTP(sameOriginRec, sameOriginReq)

	if sameOriginRec.Code != http.StatusOK {
		t.Fatalf("same-origin login status = %d, want %d; body=%s", sameOriginRec.Code, http.StatusOK, sameOriginRec.Body.String())
	}

	originalHops := requestip.TrustedProxyHops()
	requestip.SetTrustedProxyHops(1)
	defer requestip.SetTrustedProxyHops(originalHops)

	proxyReq := httptest.NewRequest(http.MethodPost, "http://nas.example.test/api/v1/auth/login", strings.NewReader(loginBody))
	proxyReq.RemoteAddr = "127.0.0.1:1234"
	proxyReq.Header.Set("Content-Type", "application/json")
	proxyReq.Header.Set("Origin", "https://nas.example.test")
	proxyReq.Header.Set("X-Forwarded-Proto", "https")
	proxyRec := httptest.NewRecorder()

	server.Router().ServeHTTP(proxyRec, proxyReq)

	if proxyRec.Code != http.StatusOK {
		t.Fatalf("trusted proxy same-origin login status = %d, want %d; body=%s", proxyRec.Code, http.StatusOK, proxyRec.Body.String())
	}

	token := loginAndGetAccessToken(t, server, username, password)
	apiClientReq := httptest.NewRequest(http.MethodPost, "/api/v1/auth/download-session", nil)
	apiClientReq.Host = "nas.example.test"
	apiClientReq.Header.Set("Authorization", "Bearer "+token)
	apiClientReq.Header.Set("Origin", "https://evil.example.test")
	apiClientRec := httptest.NewRecorder()

	server.Router().ServeHTTP(apiClientRec, apiClientReq)

	if apiClientRec.Code != http.StatusOK {
		t.Fatalf("authorization client status = %d, want %d; body=%s", apiClientRec.Code, http.StatusOK, apiClientRec.Body.String())
	}

	malformedBearerReq := httptest.NewRequest(http.MethodPost, "/api/v1/auth/download-session", nil)
	malformedBearerReq.Host = "nas.example.test"
	malformedBearerReq.Header.Set("Authorization", "Bearer "+token+" extra")
	malformedBearerReq.Header.Set("Origin", "https://evil.example.test")
	malformedBearerRec := httptest.NewRecorder()

	server.Router().ServeHTTP(malformedBearerRec, malformedBearerReq)

	if malformedBearerRec.Code != http.StatusForbidden {
		t.Fatalf("malformed bearer cross-origin status = %d, want %d; body=%s", malformedBearerRec.Code, http.StatusForbidden, malformedBearerRec.Body.String())
	}

	basicAuthReq := httptest.NewRequest(http.MethodPost, "/api/v1/auth/download-session", nil)
	basicAuthReq.Host = "nas.example.test"
	basicAuthReq.SetBasicAuth("admin", "password")
	basicAuthReq.Header.Set("Origin", "https://evil.example.test")
	basicAuthRec := httptest.NewRecorder()

	server.Router().ServeHTTP(basicAuthRec, basicAuthReq)

	if basicAuthRec.Code != http.StatusForbidden {
		t.Fatalf("basic authorization cross-origin status = %d, want %d; body=%s", basicAuthRec.Code, http.StatusForbidden, basicAuthRec.Body.String())
	}
}

