func TestServer_Login_DoesNotTrustSpoofedForwardedHeadersFromUntrustedRemote(t *testing.T) {
	server, _, _, username, _ := setupAuthServer(t)

	body := fmt.Sprintf(`{"username":"%s","password":"wrong-password"}`, username)
	for attempt := 1; attempt <= 5; attempt++ {
		req := httptest.NewRequest(http.MethodPost, "/api/v1/auth/login", strings.NewReader(body))
		req.RemoteAddr = "203.0.113.10:4123"
		req.Header.Set("X-Forwarded-For", fmt.Sprintf("198.51.100.%d", attempt))
		w := httptest.NewRecorder()

		server.Router().ServeHTTP(w, req)

		wantStatus := http.StatusUnauthorized
		wantCode := "INVALID_CREDENTIALS"
		if attempt == 5 {
			wantStatus = http.StatusTooManyRequests
			wantCode = "LOGIN_RATE_LIMITED"
		}
		if w.Code != wantStatus {
			t.Fatalf("attempt %d status = %d, want %d; body=%s", attempt, w.Code, wantStatus, w.Body.String())
		}

		var envelope struct {
			Error *struct {
				Code string `json:"code"`
			} `json:"error"`
		}
		if err := json.Unmarshal(w.Body.Bytes(), &envelope); err != nil {
			t.Fatalf("attempt %d failed to decode response: %v", attempt, err)
		}
		if envelope.Error == nil || envelope.Error.Code != wantCode {
			t.Fatalf("attempt %d error code = %+v, want %q", attempt, envelope.Error, wantCode)
		}
	}
}

func TestServer_LoginRateLimitSendsThrottledAlertEvent(t *testing.T) {
	server, _, _, username, _ := setupAuthServer(t)
	monitor := &fakeAlertMonitor{}
	server.alertMonitor = monitor

	body := fmt.Sprintf(`{"username":"%s","password":"wrong-password"}`, username)
	for attempt := 1; attempt <= 5; attempt++ {
		req := httptest.NewRequest(http.MethodPost, "/api/v1/auth/login", strings.NewReader(body))
		req.RemoteAddr = "203.0.113.10:4123"
		w := httptest.NewRecorder()

		server.Router().ServeHTTP(w, req)

		if attempt < 5 && w.Code != http.StatusUnauthorized {
			t.Fatalf("attempt %d status = %d, want %d", attempt, w.Code, http.StatusUnauthorized)
		}
		if attempt == 5 && w.Code != http.StatusTooManyRequests {
			t.Fatalf("attempt %d status = %d, want %d", attempt, w.Code, http.StatusTooManyRequests)
		}
	}

	event := waitForFakeAlertEvent(t, monitor, "login_rate_limited")
	if event.Level != alerts.AlertLevelWarning {
		t.Fatalf("login alert level = %q, want warning", event.Level)
	}
	if _, ok := event.Details["username"]; ok {
		t.Fatalf("login alert details exposed username: %+v", event.Details)
	}
	if _, ok := event.Details["client_ip"]; ok {
		t.Fatalf("login alert details exposed client_ip: %+v", event.Details)
	}
	if event.Details["trigger"] != "rate_limited" ||
		event.Details["key_scope"] != "username_client_ip" ||
		event.Details["username_status"] != "provided" ||
		event.Details["client_ip_scope"] != "public" {
		t.Fatalf("unexpected login alert details: %+v", event.Details)
	}
	detailsJSON, err := json.Marshal(event.Details)
	if err != nil {
		t.Fatalf("marshal login alert details: %v", err)
	}
	if strings.Contains(string(detailsJSON), username) || strings.Contains(string(detailsJSON), "203.0.113.10") {
		t.Fatalf("login alert details leaked raw login metadata: %s", detailsJSON)
	}

	req := httptest.NewRequest(http.MethodPost, "/api/v1/auth/login", strings.NewReader(body))
	req.RemoteAddr = "203.0.113.10:4123"
	w := httptest.NewRecorder()
	server.Router().ServeHTTP(w, req)
	if w.Code != http.StatusTooManyRequests {
		t.Fatalf("post-lock status = %d, want %d", w.Code, http.StatusTooManyRequests)
	}
	if got := fakeAlertEventCount(monitor); got != 1 {
		t.Fatalf("expected login rate-limit alert to be throttled, got %d events", got)
	}
}

