func TestServer_PublicSharePasswordNonPostDoesNotRecordFailure(t *testing.T) {
	tests := []struct {
		name      string
		path      func(string) string
		wantAllow string
	}{
		{
			name:      "short share route",
			wantAllow: "GET, POST",
			path: func(shareID string) string {
				return "/s/" + shareID
			},
		},
		{
			name:      "api share route",
			wantAllow: http.MethodPost,
			path: func(shareID string) string {
				return "/api/v1/public/shares/" + shareID + "/access"
			},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			server, _ := setupShareServer(t)
			passwordShare, err := server.shareStore.Create(share.CreateShareOptions{
				Path:      "/docs",
				Type:      share.ShareTypeFolder,
				CreatedBy: "tester",
				Password:  "secret",
			})
			if err != nil {
				t.Fatalf("create password share error: %v", err)
			}

			for attempt := 0; attempt < 5; attempt++ {
				req := httptest.NewRequest(http.MethodPut, tt.path(passwordShare.ID), strings.NewReader(`{"password":"wrong"}`))
				req.Header.Set("Content-Type", "application/json")
				w := httptest.NewRecorder()
				server.Router().ServeHTTP(w, req)

				if w.Code != http.StatusMethodNotAllowed {
					t.Fatalf("PUT password access attempt %d status = %d, want %d; body=%s", attempt+1, w.Code, http.StatusMethodNotAllowed, w.Body.String())
				}
				if allow := w.Header().Get("Allow"); allow != tt.wantAllow {
					t.Fatalf("PUT password access attempt %d Allow = %q, want %q", attempt+1, allow, tt.wantAllow)
				}
				var payload struct {
					Error *struct {
						Code string `json:"code"`
					} `json:"error"`
				}
				if err := json.Unmarshal(w.Body.Bytes(), &payload); err != nil {
					t.Fatalf("PUT password access attempt %d decode error response: %v", attempt+1, err)
				}
				if payload.Error == nil || payload.Error.Code != "METHOD_NOT_ALLOWED" {
					t.Fatalf("PUT password access attempt %d error = %+v, want METHOD_NOT_ALLOWED", attempt+1, payload.Error)
				}
			}

			successReq := httptest.NewRequest(http.MethodPost, tt.path(passwordShare.ID), strings.NewReader(`{"password":"secret"}`))
			successReq.Header.Set("Content-Type", "application/json")
			successRecorder := httptest.NewRecorder()
			server.Router().ServeHTTP(successRecorder, successReq)

			if successRecorder.Code != http.StatusOK {
				t.Fatalf("POST after non-POST attempts status = %d, want %d; body=%s", successRecorder.Code, http.StatusOK, successRecorder.Body.String())
			}
		})
	}
}

func TestServer_CreateShare_UsesBaseURL(t *testing.T) {
	server, _ := setupShareServerWithBaseURL(t, "https://nas.example.com/")

	body := `{"path":"/docs/a.txt","type":"file"}`
	req := httptest.NewRequest("POST", "/api/v1/shares", strings.NewReader(body))
	w := httptest.NewRecorder()

	server.Router().ServeHTTP(w, req)

	if w.Code != http.StatusCreated {
		t.Fatalf("create share status = %d, want %d", w.Code, http.StatusCreated)
	}

	var payload map[string]any
	if err := json.Unmarshal(w.Body.Bytes(), &payload); err != nil {
		t.Fatalf("failed to parse response JSON: %v", err)
	}

	data, ok := payload["data"].(map[string]any)
	if !ok {
		t.Fatalf("expected response envelope data")
	}
	urlValue, ok := data["url"].(string)
	if !ok {
		t.Fatalf("expected url in response")
	}
	if !strings.HasPrefix(urlValue, "https://nas.example.com/s/") {
		t.Fatalf("expected base URL applied, got %q", urlValue)
	}
	if strings.Contains(urlValue, "https://nas.example.com//s/") {
		t.Fatalf("expected trimmed base URL, got %q", urlValue)
	}
}

func TestServer_ListShares_IncludesCreatedSharesWhenAuthDisabled(t *testing.T) {
	server, _ := setupShareServer(t)

	createReq := httptest.NewRequest(http.MethodPost, "/api/v1/shares", strings.NewReader(`{"path":"/docs/a.txt","type":"file"}`))
	createReq.Header.Set("Content-Type", "application/json")
	createRec := httptest.NewRecorder()
	server.Router().ServeHTTP(createRec, createReq)

	if createRec.Code != http.StatusCreated {
		t.Fatalf("create share status = %d, want %d", createRec.Code, http.StatusCreated)
	}

	listReq := httptest.NewRequest(http.MethodGet, "/api/v1/shares", nil)
	listRec := httptest.NewRecorder()
	server.Router().ServeHTTP(listRec, listReq)

	if listRec.Code != http.StatusOK {
		t.Fatalf("list shares status = %d, want %d", listRec.Code, http.StatusOK)
	}

	var payload struct {
		Success bool `json:"success"`
		Data    []struct {
			Path string `json:"path"`
		} `json:"data"`
	}
	if err := json.Unmarshal(listRec.Body.Bytes(), &payload); err != nil {
		t.Fatalf("failed to parse response JSON: %v", err)
	}
	if !payload.Success {
		t.Fatalf("expected success response, got %s", listRec.Body.String())
	}

	found := false
	for _, item := range payload.Data {
		if item.Path == "/docs/a.txt" {
			found = true
			break
		}
	}
	if !found {
		t.Fatalf("expected auth-disabled share list to include created share, got %s", listRec.Body.String())
	}
}

