func TestServer_UpdateSettings_UpdatesSharePathPolicyRules(t *testing.T) {
	server, _ := setupShareServer(t)

	updateReq := httptest.NewRequest(http.MethodPut, "/api/v1/settings", strings.NewReader(`{"share":{"policy_rules":[{"path":"/docs/","require_password":true,"max_expires_in":"24h","max_access":5,"allowed_users":["Alice"],"allowed_groups":["Family"],"allowed_roles":["User"]}]}}`))
	updateReq.Header.Set("Content-Type", "application/json")
	updateRec := httptest.NewRecorder()
	server.Router().ServeHTTP(updateRec, updateReq)

	if updateRec.Code != http.StatusOK {
		t.Fatalf("update share policy rules status = %d, want %d; body=%s", updateRec.Code, http.StatusOK, updateRec.Body.String())
	}

	policyReq := httptest.NewRequest(http.MethodGet, "/api/v1/shares/policy", nil)
	policyRec := httptest.NewRecorder()
	server.Router().ServeHTTP(policyRec, policyReq)

	if policyRec.Code != http.StatusOK {
		t.Fatalf("get share policy status = %d, want %d; body=%s", policyRec.Code, http.StatusOK, policyRec.Body.String())
	}
	var payload map[string]any
	if err := json.Unmarshal(policyRec.Body.Bytes(), &payload); err != nil {
		t.Fatalf("failed to parse policy response: %v", err)
	}
	data, ok := payload["data"].(map[string]any)
	if !ok {
		t.Fatalf("expected policy response data")
	}
	rules, ok := data["policy_rules"].([]any)
	if !ok || len(rules) != 1 {
		t.Fatalf("expected one policy rule, got %#v", data["policy_rules"])
	}
	rule, ok := rules[0].(map[string]any)
	if !ok {
		t.Fatalf("expected policy rule object, got %#v", rules[0])
	}
	if rule["path"] != "/docs" || rule["require_password"] != true || rule["max_expires_in"] != "24h" || rule["max_access"] != float64(5) {
		t.Fatalf("unexpected policy rule: %#v", rule)
	}
	if got, want := strings.Join(anyStringSliceForTest(t, rule["allowed_users"]), ","), "alice"; got != want {
		t.Fatalf("policy rule allowed users = %q, want %q", got, want)
	}
	if got, want := strings.Join(anyStringSliceForTest(t, rule["allowed_groups"]), ","), "family"; got != want {
		t.Fatalf("policy rule allowed groups = %q, want %q", got, want)
	}
	if got, want := strings.Join(anyStringSliceForTest(t, rule["allowed_roles"]), ","), "user"; got != want {
		t.Fatalf("policy rule allowed roles = %q, want %q", got, want)
	}
}

func anyStringSliceForTest(t *testing.T, value any) []string {
	t.Helper()

	values, ok := value.([]any)
	if !ok {
		t.Fatalf("expected JSON string array, got %#v", value)
	}
	result := make([]string, 0, len(values))
	for _, value := range values {
		text, ok := value.(string)
		if !ok {
			t.Fatalf("expected JSON string item, got %#v", value)
		}
		result = append(result, text)
	}
	return result
}

func TestServer_UpdateSettings_SaveFailureDoesNotUpdateRunningShareBaseURL(t *testing.T) {
	server, _ := setupShareServerWithBaseURL(t, "https://old.example.com/")
	server.configPath = t.TempDir()

	updateBody := `{"share":{"base_url":"https://new.example.com/base/"}}`
	updateReq := httptest.NewRequest(http.MethodPut, "/api/v1/settings", strings.NewReader(updateBody))
	updateReq.Header.Set("Content-Type", "application/json")
	updateRec := httptest.NewRecorder()

	server.Router().ServeHTTP(updateRec, updateReq)

	if updateRec.Code != http.StatusInternalServerError {
		t.Fatalf("update settings share base url save failure status = %d, want %d", updateRec.Code, http.StatusInternalServerError)
	}

	createBody := `{"path":"/docs/a.txt","type":"file"}`
	createReq := httptest.NewRequest(http.MethodPost, "/api/v1/shares", strings.NewReader(createBody))
	createRec := httptest.NewRecorder()

	server.Router().ServeHTTP(createRec, createReq)

	if createRec.Code != http.StatusCreated {
		t.Fatalf("create share status = %d, want %d", createRec.Code, http.StatusCreated)
	}

	var payload map[string]any
	if err := json.Unmarshal(createRec.Body.Bytes(), &payload); err != nil {
		t.Fatalf("failed to parse response JSON: %v", err)
	}

	data, ok := payload["data"].(map[string]any)
	if !ok {
		t.Fatalf("expected response envelope data")
	}
	urlValue, ok := data["url"].(string)
	if !ok {
		t.Fatalf("expected url in response")
	}
	if !strings.HasPrefix(urlValue, "https://old.example.com/s/") {
		t.Fatalf("expected old running share base URL after save failure, got %q", urlValue)
	}
}

