	cfg.Alerts.ThresholdPct = 85
	cfg.Alerts.CriticalPct = 92
	cfg.Alerts.MinFreeBytes = 20 * 1024 * 1024 * 1024
	cfg.Alerts.CooldownPeriod = 2 * time.Hour
