func TestValidatePath(t *testing.T) {
	tests := []struct {
		input   string
		want    string
		wantErr bool
	}{
		{"/foo/bar", "/foo/bar", false},
		{"foo/bar", "/foo/bar", false},
		{"/", "/", false},
		{"", "/", false},
		{"foo..txt", "/foo..txt", false},
		{"/nested/foo..txt", "/nested/foo..txt", false},
		{"/nul\x00byte", "", true},
		{"/report\n2026.txt", "", true},
		{"/report\x7f2026.txt", "", true},
		{"../etc/passwd", "", true},
		{"/foo/../bar", "", true},
		{"..\\etc\\passwd", "", true},
		{"/safe\\..\\secret.txt", "", true},
		{"/docs/./report.pdf", "", true},
		{"/docs/.", "", true},
		{"./docs/report.pdf", "", true},
	}

	for _, tt := range tests {
		got, err := validatePath(tt.input)
		if (err != nil) != tt.wantErr {
			t.Errorf("validatePath(%q) error = %v, wantErr %v", tt.input, err, tt.wantErr)
			continue
		}
		if got != tt.want {
			t.Errorf("validatePath(%q) = %q, want %q", tt.input, got, tt.want)
		}
	}
}

func TestMapDescendantPathRejectsNonDescendants(t *testing.T) {
	tests := []struct {
		name            string
		sourceRoot      string
		destinationRoot string
		currentPath     string
		wantPath        string
		wantOK          bool
	}{
		{
			name:            "direct child",
			sourceRoot:      "/docs",
			destinationRoot: "/archive",
			currentPath:     "/docs/report.txt",
			wantPath:        "/archive/report.txt",
			wantOK:          true,
		},
		{
			name:            "same source root",
			sourceRoot:      "/docs",
			destinationRoot: "/archive",
			currentPath:     "/docs",
			wantPath:        "/archive",
			wantOK:          true,
		},
		{
			name:            "root child",
			sourceRoot:      "/",
			destinationRoot: "/archive",
			currentPath:     "/report.txt",
			wantPath:        "/archive/report.txt",
			wantOK:          true,
		},
		{
			name:            "similar prefix sibling",
			sourceRoot:      "/docs",
			destinationRoot: "/archive",
			currentPath:     "/docs-archive/secret.txt",
			wantOK:          false,
		},
		{
			name:            "parent path",
			sourceRoot:      "/docs",
			destinationRoot: "/archive",
			currentPath:     "/",
			wantOK:          false,
		},
		{
			name:            "root source does not map root itself",
			sourceRoot:      "/",
			destinationRoot: "/archive",
			currentPath:     "/",
			wantOK:          false,
		},
		{
			name:            "dirty source root",
			sourceRoot:      "/docs/.",
			destinationRoot: "/archive",
			currentPath:     "/docs/report.txt",
			wantOK:          false,
		},
		{
			name:            "relative destination root",
			sourceRoot:      "/docs",
			destinationRoot: "archive",
			currentPath:     "/docs/report.txt",
			wantOK:          false,
		},
		{
			name:            "dirty destination root",
			sourceRoot:      "/docs",
			destinationRoot: "/archive/../public",
			currentPath:     "/docs/report.txt",
			wantOK:          false,
		},
		{
			name:            "dirty current path",
			sourceRoot:      "/docs",
			destinationRoot: "/archive",
			currentPath:     "/docs/./report.txt",
			wantOK:          false,
		},
		{
			name:            "current path with query",
			sourceRoot:      "/docs",
			destinationRoot: "/archive",
			currentPath:     "/docs/report.txt?download",
			wantOK:          false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			gotPath, gotOK := mapDescendantPath(tt.sourceRoot, tt.destinationRoot, tt.currentPath)
			if gotOK != tt.wantOK || gotPath != tt.wantPath {
				t.Fatalf("mapDescendantPath() = (%q, %v), want (%q, %v)", gotPath, gotOK, tt.wantPath, tt.wantOK)
			}
		})
	}
}

func TestAPIReadDirChildPathRejectsNonDirectChildren(t *testing.T) {
	tests := []struct {
		name      string
		parent    string
		child     *storage.FileInfo
		wantPath  string
		wantName  string
		wantError bool
	}{
		{
			name:     "direct child",
			parent:   "/docs",
			child:    &storage.FileInfo{Path: "/docs/report.txt", Name: "report.txt"},
			wantPath: "/docs/report.txt",
			wantName: "report.txt",
		},
		{
			name:     "root direct child",
			parent:   "/",
			child:    &storage.FileInfo{Path: "/report.txt", Name: "report.txt"},
			wantPath: "/report.txt",
			wantName: "report.txt",
		},
		{
			name:     "fallback from blank path",
			parent:   "/docs",
			child:    &storage.FileInfo{Name: "report.txt"},
			wantPath: "/docs/report.txt",
			wantName: "report.txt",
		},
		{
			name:      "dot segment child path",
			parent:    "/docs",
			child:     &storage.FileInfo{Path: "/docs/./report.txt", Name: "report.txt"},
			wantError: true,
		},
		{
			name:      "parent segment child path",
			parent:    "/docs",
			child:     &storage.FileInfo{Path: "/docs/../report.txt", Name: "report.txt"},
			wantError: true,
		},
		{
			name:      "dot segment fallback name",
			parent:    "/docs",
			child:     &storage.FileInfo{Name: "./report.txt"},
			wantError: true,
		},
		{
			name:      "leading slash fallback name",
			parent:    "/docs",
			child:     &storage.FileInfo{Name: "/report.txt"},
			wantError: true,
		},
		{
			name:      "trailing slash fallback name",
			parent:    "/docs",
			child:     &storage.FileInfo{Name: "report.txt/"},
			wantError: true,
		},
		{
			name:      "backslash fallback name",
			parent:    "/docs",
			child:     &storage.FileInfo{Name: "nested\\report.txt"},
			wantError: true,
		},
		{
			name:      "control character child path",
			parent:    "/docs",
			child:     &storage.FileInfo{Path: "/docs/report\n2026.txt", Name: "report\n2026.txt"},
			wantError: true,
		},
		{
			name:      "backslash child path",
			parent:    "/docs",
			child:     &storage.FileInfo{Path: "/docs\\report.txt", Name: "report.txt"},
			wantError: true,
		},
		{
			name:      "control character fallback name",
			parent:    "/docs",
			child:     &storage.FileInfo{Name: "report\x7f.txt"},
			wantError: true,
		},
		{
			name:      "similar prefix sibling",
			parent:    "/docs",
			child:     &storage.FileInfo{Path: "/docs-archive/secret.txt", Name: "secret.txt"},
			wantError: true,
		},
		{
			name:      "nested descendant",
			parent:    "/docs",
			child:     &storage.FileInfo{Path: "/docs/nested/secret.txt", Name: "secret.txt"},
			wantError: true,
		},
		{
			name:      "same path",
			parent:    "/docs",
			child:     &storage.FileInfo{Path: "/docs", Name: "docs"},
			wantError: true,
		},
		{
			name:      "nil child",
			parent:    "/docs",
			child:     nil,
			wantError: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			gotPath, gotName, err := apiReadDirChildPath(tt.parent, tt.child)
			if (err != nil) != tt.wantError {
				t.Fatalf("apiReadDirChildPath() error = %v, wantError %v", err, tt.wantError)
			}
			if gotPath != tt.wantPath || gotName != tt.wantName {
				t.Fatalf("apiReadDirChildPath() = (%q, %q), want (%q, %q)", gotPath, gotName, tt.wantPath, tt.wantName)
			}
		})
	}
}

func TestAPINormalizeReadDirChildrenRejectsNonDirectChildren(t *testing.T) {
	children := []*storage.FileInfo{
		{Path: "/docs/readme.txt", Name: "readme.txt"},
		{Path: "/docs-archive/secret.txt", Name: "secret.txt"},
	}

	if _, err := apiNormalizeReadDirChildren("/docs", children); err == nil {
		t.Fatal("apiNormalizeReadDirChildren() error = nil, want non-direct child rejection")
	}

	normalized, err := apiNormalizeReadDirChildren("/docs", []*storage.FileInfo{
		nil,
		{Name: "readme.txt"},
		{Path: "/docs/report.txt", Name: "report.txt"},
	})
	if err != nil {
		t.Fatalf("apiNormalizeReadDirChildren() error = %v", err)
	}
	if len(normalized) != 2 {
		t.Fatalf("apiNormalizeReadDirChildren() returned %d entries, want 2", len(normalized))
	}
	if normalized[0].Path != "/docs/readme.txt" || normalized[1].Path != "/docs/report.txt" {
		t.Fatalf("apiNormalizeReadDirChildren() paths = %q, %q", normalized[0].Path, normalized[1].Path)
	}
}

