func TestServer_MoveFile_RollsBackWhenFavoritePathSyncFails(t *testing.T) {
	server, fs, tmpDir := setupTestServer(t)
	ctx := context.Background()

	if err := fs.Mkdir(ctx, "/docs"); err != nil {
		t.Fatalf("Mkdir(/docs) error: %v", err)
	}
	if err := fs.Mkdir(ctx, "/archive"); err != nil {
		t.Fatalf("Mkdir(/archive) error: %v", err)
	}
	if err := fs.WriteFile(ctx, "/docs/report.txt", bytes.NewReader([]byte("report"))); err != nil {
		t.Fatalf("WriteFile(/docs/report.txt) error: %v", err)
	}

	shareDir := filepath.Join(tmpDir, "move-hook-share")
	if err := os.MkdirAll(shareDir, 0o755); err != nil {
		t.Fatalf("MkdirAll(shareDir) error: %v", err)
	}
	shareStore, err := share.NewShareStore(filepath.Join(shareDir, "shares.json"))
	if err != nil {
		t.Fatalf("NewShareStore() error: %v", err)
	}
	folderShare, err := shareStore.Create(share.CreateShareOptions{Path: "/docs", Type: share.ShareTypeFolder, CreatedBy: "tester"})
	if err != nil {
		t.Fatalf("Create(folder share) error: %v", err)
	}
	fileShare, err := shareStore.Create(share.CreateShareOptions{Path: "/docs/report.txt", Type: share.ShareTypeFile, CreatedBy: "tester"})
	if err != nil {
		t.Fatalf("Create(file share) error: %v", err)
	}

	favoritesDir := filepath.Join(tmpDir, "move-hook-favorites")
	if err := os.MkdirAll(favoritesDir, 0o755); err != nil {
		t.Fatalf("MkdirAll(favoritesDir) error: %v", err)
	}
	favoritesStore, err := favorites.NewStore(filepath.Join(favoritesDir, "favorites.json"))
	if err != nil {
		t.Fatalf("NewStore() error: %v", err)
	}
	if _, err := favoritesStore.Add("tester", "/docs", "folder"); err != nil {
		t.Fatalf("Add(/docs) error: %v", err)
	}
	if _, err := favoritesStore.Add("tester", "/docs/report.txt", "file"); err != nil {
		t.Fatalf("Add(/docs/report.txt) error: %v", err)
	}

	server.shareStore = shareStore
	server.favoritesStore = favoritesStore

	if err := os.Chmod(favoritesDir, 0o500); err != nil {
		t.Fatalf("Chmod(favoritesDir) error: %v", err)
	}
	defer func() {
		_ = os.Chmod(favoritesDir, 0o755)
	}()

	body := `{"from":"/docs","to":"/archive/docs"}`
	req := httptest.NewRequest(http.MethodPost, "/api/v1/files-move", strings.NewReader(body))
	req.Header.Set("Content-Type", "application/json")
	w := httptest.NewRecorder()

	server.Router().ServeHTTP(w, req)

	if w.Code != http.StatusInternalServerError {
		t.Fatalf("move with favorites sync failure status = %d, want %d", w.Code, http.StatusInternalServerError)
	}
	if _, err := fs.Stat(ctx, "/docs/report.txt"); err != nil {
		t.Fatalf("expected original file path to remain after rollback, got %v", err)
	}
	if _, err := fs.Stat(ctx, "/archive/docs/report.txt"); !errors.Is(err, storage.ErrNotFound) {
		t.Fatalf("expected destination file to be absent after rollback, got %v", err)
	}

	loadedFolderShare, err := server.shareStore.Get(folderShare.ID)
	if err != nil {
		t.Fatalf("Get(folder share) error: %v", err)
	}
	if loadedFolderShare.Path != "/docs" {
		t.Fatalf("expected folder share path rollback to /docs, got %q", loadedFolderShare.Path)
	}
	loadedFileShare, err := server.shareStore.Get(fileShare.ID)
	if err != nil {
		t.Fatalf("Get(file share) error: %v", err)
	}
	if loadedFileShare.Path != "/docs/report.txt" {
		t.Fatalf("expected file share path rollback to /docs/report.txt, got %q", loadedFileShare.Path)
	}
	if !server.favoritesStore.IsFavorite("tester", "/docs") || !server.favoritesStore.IsFavorite("tester", "/docs/report.txt") {
		t.Fatal("expected favorites to remain on original paths after rollback")
	}
	if server.favoritesStore.IsFavorite("tester", "/archive/docs") || server.favoritesStore.IsFavorite("tester", "/archive/docs/report.txt") {
		t.Fatal("expected destination favorites not to be persisted after rollback")
	}
}

func TestServer_HandlePathRenamed_RollbackIgnoresSharePersistenceWarning(t *testing.T) {
	server, _, tmpDir := setupTestServer(t)

	shareDir := filepath.Join(tmpDir, "rename-rollback-share-warning")
	if err := os.MkdirAll(shareDir, 0o755); err != nil {
		t.Fatalf("MkdirAll(shareDir) error: %v", err)
	}
	shareStore, err := share.NewShareStore(filepath.Join(shareDir, "shares.json"))
	if err != nil {
		t.Fatalf("NewShareStore() error: %v", err)
	}
	folderShare, err := shareStore.Create(share.CreateShareOptions{Path: "/docs", Type: share.ShareTypeFolder, CreatedBy: "tester"})
	if err != nil {
		t.Fatalf("Create(folder share) error: %v", err)
	}
	fileShare, err := shareStore.Create(share.CreateShareOptions{Path: "/docs/report.txt", Type: share.ShareTypeFile, CreatedBy: "tester"})
	if err != nil {
		t.Fatalf("Create(file share) error: %v", err)
	}

	favoritesDir := filepath.Join(tmpDir, "rename-rollback-favorites-warning")
	if err := os.MkdirAll(favoritesDir, 0o755); err != nil {
		t.Fatalf("MkdirAll(favoritesDir) error: %v", err)
	}
	favoritesStore, err := favorites.NewStore(filepath.Join(favoritesDir, "favorites.json"))
	if err != nil {
		t.Fatalf("NewStore() error: %v", err)
	}
	if _, err := favoritesStore.Add("tester", "/docs", "folder"); err != nil {
		t.Fatalf("Add(/docs) error: %v", err)
	}

	server.shareStore = shareStore
	server.favoritesStore = favoritesStore

	if err := os.Chmod(favoritesDir, 0o500); err != nil {
		t.Fatalf("Chmod(favoritesDir) error: %v", err)
	}
	defer func() {
		_ = os.Chmod(favoritesDir, 0o755)
	}()

	callCount := 0
	restoreSync := share.SetSyncShareStoreRootDirForTest(func(root *os.Root) error {
		callCount++
		if callCount == 2 {
			return errors.New("directory fsync failed")
		}
		return nil
	})
	defer restoreSync()

	err = server.handlePathRenamed(context.Background(), "/docs", "/archive/docs")
	if err == nil {
		t.Fatal("expected handlePathRenamed() to fail because favorites sync fails")
	}
	if !strings.Contains(err.Error(), "sync favorite paths after rename") {
		t.Fatalf("expected favorite sync failure, got %v", err)
	}
	if strings.Contains(err.Error(), "rollback share paths after rename") {
		t.Fatalf("expected rollback warning to be ignored, got %v", err)
	}

	loadedFolderShare, err := shareStore.Get(folderShare.ID)
	if err != nil {
		t.Fatalf("Get(folder share) error: %v", err)
	}
	if loadedFolderShare.Path != "/docs" {
		t.Fatalf("expected folder share path rollback to /docs, got %q", loadedFolderShare.Path)
	}
	loadedFileShare, err := shareStore.Get(fileShare.ID)
	if err != nil {
		t.Fatalf("Get(file share) error: %v", err)
	}
	if loadedFileShare.Path != "/docs/report.txt" {
		t.Fatalf("expected file share path rollback to /docs/report.txt, got %q", loadedFileShare.Path)
	}

	reloadedStore, err := share.NewShareStore(filepath.Join(shareDir, "shares.json"))
	if err != nil {
		t.Fatalf("NewShareStore(reload) error: %v", err)
	}
	reloadedFolderShare, err := reloadedStore.Get(folderShare.ID)
	if err != nil {
		t.Fatalf("Get(reloaded folder share) error: %v", err)
	}
	if reloadedFolderShare.Path != "/docs" {
		t.Fatalf("expected persisted folder share path rollback to /docs, got %q", reloadedFolderShare.Path)
	}
}

func TestServer_MoveFile_RollbackDoesNotMoveUnrelatedDestinationSharesWhenFavoriteSyncFails(t *testing.T) {
	if os.PathSeparator == '\\' {
		t.Skip("permission-backed save failure test requires unix-like directory permission semantics")
	}

	server, fs, tmpDir := setupTestServer(t)
	ctx := context.Background()

	if err := fs.Mkdir(ctx, "/docs"); err != nil {
		t.Fatalf("Mkdir(/docs) error: %v", err)
	}
	if err := fs.Mkdir(ctx, "/archive"); err != nil {
		t.Fatalf("Mkdir(/archive) error: %v", err)
	}
	if err := fs.Mkdir(ctx, "/archive/docs"); err != nil {
		t.Fatalf("Mkdir(/archive/docs) error: %v", err)
	}
	if err := fs.WriteFile(ctx, "/docs/report.txt", bytes.NewReader([]byte("report"))); err != nil {
		t.Fatalf("WriteFile(/docs/report.txt) error: %v", err)
	}

	shareFilePath := filepath.Join(tmpDir, "move-share-rollback-unrelated.json")
	favoritesDir := filepath.Join(tmpDir, "move-favorites-rollback-unrelated")
	if err := os.MkdirAll(favoritesDir, 0o755); err != nil {
		t.Fatalf("MkdirAll(favoritesDir) error: %v", err)
	}
	favoritesFilePath := filepath.Join(favoritesDir, "favorites.json")

	shareStore, err := share.NewShareStore(shareFilePath)
	if err != nil {
		t.Fatalf("NewShareStore() error: %v", err)
	}
	movedShare, err := shareStore.Create(share.CreateShareOptions{Path: "/docs/report.txt", Type: share.ShareTypeFile, CreatedBy: "tester"})
	if err != nil {
		t.Fatalf("Create(moved share) error: %v", err)
	}
	unrelatedShare, err := shareStore.Create(share.CreateShareOptions{Path: "/archive/docs/report.txt", Type: share.ShareTypeFile, CreatedBy: "tester"})
	if err != nil {
		t.Fatalf("Create(unrelated share) error: %v", err)
	}

	favoritesStore, err := favorites.NewStore(favoritesFilePath)
	if err != nil {
		t.Fatalf("NewStore() error: %v", err)
	}
	if _, err := favoritesStore.Add("tester", "/docs/report.txt", "file"); err != nil {
		t.Fatalf("AddFavorite() error: %v", err)
	}

	server.shareStore = shareStore
	server.favoritesStore = favoritesStore

	if err := os.Chmod(favoritesDir, 0o500); err != nil {
		t.Fatalf("Chmod(favoritesDir) error: %v", err)
	}
	defer func() {
		_ = os.Chmod(favoritesDir, 0o755)
	}()

	body := `{"from":"/docs/report.txt","to":"/archive/docs/report.txt"}`
	req := httptest.NewRequest(http.MethodPost, "/api/v1/files-move", strings.NewReader(body))
	req.Header.Set("Content-Type", "application/json")
	w := httptest.NewRecorder()

	server.Router().ServeHTTP(w, req)

	if w.Code != http.StatusInternalServerError {
		t.Fatalf("move with favorites sync failure status = %d, want %d", w.Code, http.StatusInternalServerError)
	}
	if _, err := fs.Stat(ctx, "/docs/report.txt"); err != nil {
		t.Fatalf("expected original file path to remain after rollback, got %v", err)
	}
	if _, err := fs.Stat(ctx, "/archive/docs/report.txt"); !errors.Is(err, storage.ErrNotFound) {
		t.Fatalf("expected destination file to be absent after rollback, got %v", err)
	}

	loadedMovedShare, err := server.shareStore.Get(movedShare.ID)
	if err != nil {
		t.Fatalf("Get(moved share) error: %v", err)
	}
	if loadedMovedShare.Path != "/docs/report.txt" {
		t.Fatalf("expected moved share path rollback to /docs/report.txt, got %q", loadedMovedShare.Path)
	}
	loadedUnrelatedShare, err := server.shareStore.Get(unrelatedShare.ID)
	if err != nil {
		t.Fatalf("Get(unrelated share) error: %v", err)
	}
	if loadedUnrelatedShare.Path != "/archive/docs/report.txt" {
		t.Fatalf("expected unrelated destination share to remain on /archive/docs/report.txt, got %q", loadedUnrelatedShare.Path)
	}
	if shares := server.shareStore.GetByPath("/docs/report.txt"); len(shares) != 1 || shares[0].ID != movedShare.ID {
		t.Fatalf("expected original path index to contain only moved share after rollback, got %+v", shares)
	}
	if shares := server.shareStore.GetByPath("/archive/docs/report.txt"); len(shares) != 1 || shares[0].ID != unrelatedShare.ID {
		t.Fatalf("expected destination path index to contain only unrelated share after rollback, got %+v", shares)
	}
}

