func TestServer_WebDAVCredentials_UpdatesRunningConfigAfterSettingsUpdate(t *testing.T) {
	server, _, tmpDir := setupTestServer(t)
	server.configPath = path.Join(tmpDir, "config.toml")
	server.config.Storage.Root = tmpDir
	webdavUpdater := &fakeWebDAVUpdater{}
	server.updateWebDAV = webdavUpdater.UpdateConfig
	server.config.WebDAV.Enabled = true
	server.config.WebDAV.Prefix = "/dav"
	server.config.WebDAV.ReadOnly = false
	server.config.WebDAV.AuthType = "basic"
	server.config.WebDAV.Username = "runtime-user"
	server.config.WebDAV.Password = "runtime-pass"
	server.activeWebDAV = WebDAVRuntimeConfig{
		Enabled:             true,
		Prefix:              "/dav",
		ReadOnly:            false,
		AuthType:            "basic",
		Username:            "runtime-user",
		Password:            "runtime-pass",
		PasswordIsGenerated: true,
	}

	body := `{"webdav":{"enabled":true,"prefix":"/new-dav","read_only":true,"auth_type":" BASIC ","username":"saved-user","password":"saved-pass"}}`
	req := httptest.NewRequest(http.MethodPut, "/api/v1/settings", strings.NewReader(body))
	req.Header.Set("Content-Type", "application/json")
	w := httptest.NewRecorder()

	server.Router().ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Fatalf("update settings webdav status = %d, want %d", w.Code, http.StatusOK)
	}

	credsReq := httptest.NewRequest(http.MethodGet, "/api/v1/settings/webdav-credentials", nil)
	credsRec := httptest.NewRecorder()
	server.Router().ServeHTTP(credsRec, credsReq)

	if credsRec.Code != http.StatusOK {
		t.Fatalf("webdav credentials status = %d, want %d", credsRec.Code, http.StatusOK)
	}

	var payload struct {
		Data struct {
			URL      string `json:"url"`
			Username string `json:"username"`
			Password string `json:"password"`
		} `json:"data"`
	}
	if err := json.Unmarshal(credsRec.Body.Bytes(), &payload); err != nil {
		t.Fatalf("failed to parse response JSON: %v", err)
	}
	if payload.Data.URL != "/new-dav/" {
		t.Fatalf("expected running webdav url /new-dav/, got %q", payload.Data.URL)
	}
	if payload.Data.Username != "saved-user" {
		t.Fatalf("expected running webdav username saved-user, got %q", payload.Data.Username)
	}
	if payload.Data.Password != "" {
		t.Fatalf("expected custom WebDAV password to remain hidden, got %q", payload.Data.Password)
	}
	if server.config.WebDAV.Prefix != "/new-dav" {
		t.Fatalf("expected saved config prefix /new-dav, got %q", server.config.WebDAV.Prefix)
	}
	if server.config.WebDAV.AuthType != "basic" {
		t.Fatalf("expected saved WebDAV auth type basic, got %q", server.config.WebDAV.AuthType)
	}
	if server.activeWebDAV.Prefix != "/new-dav" {
		t.Fatalf("expected active WebDAV prefix /new-dav, got %q", server.activeWebDAV.Prefix)
	}
	if server.activeWebDAV.AuthType != "basic" {
		t.Fatalf("expected active WebDAV auth type basic, got %q", server.activeWebDAV.AuthType)
	}
	if !server.activeWebDAV.ReadOnly {
		t.Fatalf("expected active WebDAV read-only mode to update")
	}
	if server.activeWebDAV.Password != "saved-pass" {
		t.Fatalf("expected active WebDAV password to update, got %q", server.activeWebDAV.Password)
	}
	if server.activeWebDAV.PasswordIsGenerated {
		t.Fatalf("expected active WebDAV password to be marked custom")
	}
	if webdavUpdater.updateCount != 1 {
		t.Fatalf("expected WebDAV updater to be called once, got %d", webdavUpdater.updateCount)
	}
	if webdavUpdater.lastConfig.Prefix != "/new-dav" {
		t.Fatalf("expected WebDAV updater prefix /new-dav, got %q", webdavUpdater.lastConfig.Prefix)
	}
	if !webdavUpdater.lastConfig.ReadOnly {
		t.Fatalf("expected WebDAV updater to receive read-only=true")
	}
	if webdavUpdater.lastConfig.AuthType != "basic" {
		t.Fatalf("expected WebDAV updater auth type basic, got %q", webdavUpdater.lastConfig.AuthType)
	}
}

func TestServer_UpdateSettings_UpdatesDirectoryStorageControlsAndWebDAVRuntime(t *testing.T) {
	server, _, tmpDir := setupTestServer(t)
	server.configPath = path.Join(tmpDir, "config.toml")
	server.config.WebDAV.Enabled = true
	server.config.WebDAV.Prefix = "/dav"
	server.config.WebDAV.AuthType = "basic"
	server.config.WebDAV.Username = "webdav-user"
	server.config.WebDAV.Password = "webdav-pass"
	server.storeConfig(server.config)
	webdavUpdater := &fakeWebDAVUpdater{}
	server.updateWebDAV = webdavUpdater.UpdateConfig

	body := `{"storage":{"directory_quotas":[{"path":"/team/","quota_bytes":1048576}],"directory_access_rules":[{"path":"/team/","read_groups":["Family"],"write_groups":["Editors"]}]}}`
	req := httptest.NewRequest(http.MethodPut, "/api/v1/settings", strings.NewReader(body))
	req.Header.Set("Content-Type", "application/json")
	w := httptest.NewRecorder()
	server.Router().ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Fatalf("update directory quotas status = %d, want %d; body=%s", w.Code, http.StatusOK, w.Body.String())
	}
	if len(server.config.Storage.DirectoryQuotas) != 1 {
		t.Fatalf("directory quotas count = %d, want 1", len(server.config.Storage.DirectoryQuotas))
	}
	if got := server.config.Storage.DirectoryQuotas[0].Path; got != "/team" {
		t.Fatalf("directory quota path = %q, want /team", got)
	}
	if webdavUpdater.updateCount != 1 {
		t.Fatalf("webdav update count = %d, want 1", webdavUpdater.updateCount)
	}
	if len(webdavUpdater.lastConfig.DirectoryQuotas) != 1 || webdavUpdater.lastConfig.DirectoryQuotas[0].Path != "/team" {
		t.Fatalf("webdav runtime directory quotas = %+v", webdavUpdater.lastConfig.DirectoryQuotas)
	}
	if len(webdavUpdater.lastConfig.DirectoryAccessRules) != 1 || webdavUpdater.lastConfig.DirectoryAccessRules[0].Path != "/team" {
		t.Fatalf("webdav runtime directory access rules = %+v", webdavUpdater.lastConfig.DirectoryAccessRules)
	}
	if got, want := strings.Join(webdavUpdater.lastConfig.DirectoryAccessRules[0].ReadGroups, ","), "family"; got != want {
		t.Fatalf("webdav runtime read groups = %q, want %q", got, want)
	}

	getReq := httptest.NewRequest(http.MethodGet, "/api/v1/settings", nil)
	getW := httptest.NewRecorder()
	server.Router().ServeHTTP(getW, getReq)
	if getW.Code != http.StatusOK {
		t.Fatalf("get settings status = %d, want %d", getW.Code, http.StatusOK)
	}
	var payload struct {
		Data struct {
			Storage struct {
				DirectoryQuotas      []config.DirectoryQuotaConfig      `json:"directory_quotas"`
				DirectoryAccessRules []config.DirectoryAccessRuleConfig `json:"directory_access_rules"`
			} `json:"storage"`
		} `json:"data"`
	}
	if err := json.NewDecoder(getW.Body).Decode(&payload); err != nil {
		t.Fatalf("decode settings response error: %v", err)
	}
	if len(payload.Data.Storage.DirectoryQuotas) != 1 || payload.Data.Storage.DirectoryQuotas[0].Path != "/team" {
		t.Fatalf("settings directory quotas = %+v", payload.Data.Storage.DirectoryQuotas)
	}
	if len(payload.Data.Storage.DirectoryAccessRules) != 1 || payload.Data.Storage.DirectoryAccessRules[0].Path != "/team" {
		t.Fatalf("settings directory access rules = %+v", payload.Data.Storage.DirectoryAccessRules)
	}
}

func TestServer_UpdateSettings_SendsPolicyChangeAlert(t *testing.T) {
	server, _, tmpDir := setupTestServer(t)
	server.configPath = path.Join(tmpDir, "config.toml")
	server.config.WebDAV.Enabled = false
	server.config.Share.Enabled = false
	server.config.Share.DefaultExpiresIn = 0
	server.config.Share.DefaultMaxAccess = 0
	server.config.Share.PolicyRules = nil
	server.storeConfig(server.config)
	monitor := &fakeAlertMonitor{}
	server.alertMonitor = monitor

	body := `{"storage":{"directory_access_rules":[{"path":"/team/token=access-secret","read_groups":["Family"],"write_groups":["Editors"]}]},"share":{"enabled":true,"default_expires_in":"24h","default_max_access":10,"policy_rules":[{"path":"/team/token=share-secret","require_password":true,"max_expires_in":"24h","max_access":10}]}}`
	req := httptest.NewRequest(http.MethodPut, "/api/v1/settings", strings.NewReader(body))
	req.Header.Set("Content-Type", "application/json")
	w := httptest.NewRecorder()

	server.Router().ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Fatalf("update settings status = %d, want %d; body=%s", w.Code, http.StatusOK, w.Body.String())
	}
	if len(monitor.events) != 1 {
		t.Fatalf("policy alert event count = %d, want 1", len(monitor.events))
	}
	event := monitor.events[0]
	if event.Type != settingsPolicyChangedAlertType || event.Level != alerts.AlertLevelWarning {
		t.Fatalf("policy alert event = %s/%s, want %s/warning", event.Type, event.Level, settingsPolicyChangedAlertType)
	}
	if event.Message != "directory access and share policies changed" {
		t.Fatalf("policy alert message = %q", event.Message)
	}
	if event.Timestamp.Location() != time.UTC {
		t.Fatalf("policy alert timestamp location = %v, want UTC", event.Timestamp.Location())
	}
	if event.Details["source"] != "settings" {
		t.Fatalf("policy alert source = %#v, want settings", event.Details["source"])
	}
	if got, want := event.Details["changed_sections"], []string{"directory_access_rules", "share_policy"}; !reflect.DeepEqual(got, want) {
		t.Fatalf("policy alert changed sections = %#v, want %#v", got, want)
	}
	if event.Details["directory_access_rules_changed"] != true || event.Details["directory_access_rule_count"] != 1 {
		t.Fatalf("unexpected directory access alert details: %+v", event.Details)
	}
	if _, ok := event.Details["directory_access_rule_paths"]; ok {
		t.Fatalf("directory access rule paths must not be sent in alert details: %+v", event.Details)
	}
	for _, key := range []string{
		"share_policy_changed",
		"share_enabled_changed",
		"share_default_expiry_changed",
		"share_default_max_access_changed",
		"share_policy_rules_changed",
	} {
		if event.Details[key] != true {
			t.Fatalf("policy alert detail %s = %#v, want true; details=%+v", key, event.Details[key], event.Details)
		}
	}
	if event.Details["share_policy_rule_count"] != 1 {
		t.Fatalf("share policy rule count = %#v, want 1", event.Details["share_policy_rule_count"])
	}
	if _, ok := event.Details["share_policy_rule_paths"]; ok {
		t.Fatalf("share policy rule paths must not be sent in alert details: %+v", event.Details)
	}
	detailsJSON, err := json.Marshal(event.Details)
	if err != nil {
		t.Fatalf("marshal policy alert details: %v", err)
	}
	for _, leaked := range []string{"access-secret", "share-secret", "token=access-secret", "token=share-secret"} {
		if strings.Contains(string(detailsJSON), leaked) {
			t.Fatalf("policy alert details leaked path secret %q: %s", leaked, string(detailsJSON))
		}
	}
}

